function setText(id, val) {
    var el = document.getElementById(id);
    if (el) el.textContent = (val === '' || val === null || val === undefined) ? '' : val;
}

function parseEmployments(jsonText) {
    if (!jsonText) return [];
    try {
        var data = JSON.parse(jsonText);
        return Array.isArray(data) ? data : [];
    } catch (e) { return []; }
}

function getCurrentWorkspaceId() {
    try {
        var match = (window.location.pathname || '').match(/\/cw\/([^/]+)/);
        return match ? decodeURIComponent(match[1]) : null;
    } catch (e) { return null; }
}

function getRelevantEmploymentsForCard(card) {
    if (!card) return [];
    var script = card.querySelector('script.employment-json');
    if (!script) return [];
    var raw = (script.textContent || '').trim();
    if (!raw) return [];
    var items = parseEmployments(raw);
    if (!items.length) return [];
    var cw = getCurrentWorkspaceId();
    var relevant = cw ? items.filter(function (i) { return i && i.cw_id === cw; }) : items.slice();
    return relevant.length ? relevant : items;
}

function getCardEmploymentStatus(card) {
    var relevant = getRelevantEmploymentsForCard(card);
    if (!relevant.length) return 'working';
    return relevant.some(function (i) { return i && i.is_working === 'active'; }) ? 'working' : 'fired';
}

function closeDropdown() {
    var dd = document.getElementById('docDropdown');
    var seg = document.querySelector('.emp-seg');
    if (dd) dd.classList.remove('open');
    if (seg) seg.classList.remove('dropdown-open');
}

function toggleDropdown() {
    var dd = document.getElementById('docDropdown');
    var seg = document.querySelector('.emp-seg');
    if (!dd || !seg) return;
    if (dd.classList.contains('open')) { closeDropdown(); }
    else { dd.classList.add('open'); seg.classList.add('dropdown-open'); }
}

// Client-side filtering: employment + doc status (no server request)
function applyClientFilters() {
    if (isApplying) return;
    isApplying = true;

    var empFilter = state.empFilter;
    var docFilter = state.docFilter;

    var rows = document.querySelectorAll('.registry-row');
    rows.forEach(function (row) {
        var card = row.closest('div[class*="FPS_CARDS2__CARD"]') || row;

        // Employment filter
        var empStatus = getCardEmploymentStatus(card);
        var empVisible = (empFilter === 'working') ? empStatus === 'working' :
            (empFilter === 'fired') ? empStatus === 'fired' : true;

        if (!empVisible) {
            card.style.display = 'none';
            return;
        }

        // Doc status filter (client-side, only when working)
        if (empFilter === 'working' && docFilter !== 'all') {
            var pill = row.querySelector('.status-pill');

